#include "jayess_runtime.h"

#include <ctype.h>
#include <stdlib.h>
#include <string.h>

typedef struct jayess_xml_parser {
    const char *input;
    size_t length;
    size_t pos;
    const char *error;
} jayess_xml_parser;

typedef struct jayess_xml_buffer {
    char *data;
    size_t length;
    size_t capacity;
    int failed;
} jayess_xml_buffer;

typedef struct jayess_xml_position {
    size_t offset;
    int line;
    int column;
} jayess_xml_position;

typedef struct jayess_xml_ns_binding {
    char *prefix;
    char *uri;
    struct jayess_xml_ns_binding *next;
} jayess_xml_ns_binding;

static void jayess_xml_fail(jayess_xml_parser *parser, const char *message) {
    if (parser->error == NULL) {
        parser->error = message;
    }
}

static int jayess_xml_peek(jayess_xml_parser *parser) {
    if (parser->pos >= parser->length) {
        return -1;
    }
    return (unsigned char) parser->input[parser->pos];
}

static int jayess_xml_has_prefix(jayess_xml_parser *parser, const char *text) {
    size_t prefix_length = strlen(text);
    if (parser->pos + prefix_length > parser->length) {
        return 0;
    }
    return strncmp(parser->input + parser->pos, text, prefix_length) == 0;
}

static void jayess_xml_skip_ws(jayess_xml_parser *parser) {
    while (parser->pos < parser->length && isspace((unsigned char) parser->input[parser->pos])) {
        parser->pos++;
    }
}

static int jayess_xml_is_name_start(int ch) {
    return isalpha((unsigned char) ch) || ch == '_' || ch == ':';
}

static int jayess_xml_is_name_char(int ch) {
    return jayess_xml_is_name_start(ch) || isdigit((unsigned char) ch) || ch == '-' || ch == '.';
}

static char *jayess_xml_copy_range(const char *input, size_t start, size_t end) {
    size_t length = end > start ? end - start : 0;
    char *text = (char *) malloc(length + 1);
    if (text == NULL) {
        return NULL;
    }
    if (length > 0) {
        memcpy(text, input + start, length);
    }
    text[length] = '\0';
    return text;
}

static void jayess_xml_free_partial_object(jayess_object *object) {
    if (object != NULL) {
        jayess_object_free_unshared(object);
    }
}

static void jayess_xml_free_partial_array(jayess_array *array) {
    if (array != NULL) {
        jayess_array_free_unshared(array);
    }
}

static char *jayess_xml_strdup(const char *text) {
    size_t length;
    char *copy;
    if (text == NULL) {
        return NULL;
    }
    length = strlen(text);
    copy = (char *) malloc(length + 1);
    if (copy == NULL) {
        return NULL;
    }
    memcpy(copy, text, length + 1);
    return copy;
}

static void jayess_xml_split_name(const char *name, char **prefix_out, char **local_name_out) {
    const char *colon;
    *prefix_out = NULL;
    *local_name_out = jayess_xml_strdup(name != NULL ? name : "");
    if (name == NULL) {
        return;
    }
    colon = strchr(name, ':');
    if (colon == NULL) {
        return;
    }
    *prefix_out = jayess_xml_copy_range(name, 0, (size_t) (colon - name));
    free(*local_name_out);
    *local_name_out = jayess_xml_strdup(colon + 1);
}

static const char *jayess_xml_lookup_ns(jayess_xml_ns_binding *bindings, const char *prefix) {
    jayess_xml_ns_binding *current = bindings;
    const char *target = prefix != NULL ? prefix : "";
    while (current != NULL) {
        const char *current_prefix = current->prefix != NULL ? current->prefix : "";
        if (strcmp(current_prefix, target) == 0) {
            return current->uri;
        }
        current = current->next;
    }
    return NULL;
}

static jayess_xml_ns_binding *jayess_xml_push_ns_binding(jayess_xml_ns_binding *head, const char *prefix, const char *uri) {
    jayess_xml_ns_binding *binding = (jayess_xml_ns_binding *) malloc(sizeof(jayess_xml_ns_binding));
    if (binding == NULL) {
        return head;
    }
    binding->prefix = jayess_xml_strdup(prefix != NULL ? prefix : "");
    binding->uri = jayess_xml_strdup(uri != NULL ? uri : "");
    binding->next = head;
    return binding;
}

static void jayess_xml_free_ns_bindings_until(jayess_xml_ns_binding *head, jayess_xml_ns_binding *stop) {
    while (head != stop) {
        jayess_xml_ns_binding *next = head->next;
        free(head->prefix);
        free(head->uri);
        free(head);
        head = next;
    }
}

static char *jayess_xml_parse_name(jayess_xml_parser *parser) {
    size_t start = parser->pos;
    if (!jayess_xml_is_name_start(jayess_xml_peek(parser))) {
        return NULL;
    }
    parser->pos++;
    while (parser->pos < parser->length && jayess_xml_is_name_char((unsigned char) parser->input[parser->pos])) {
        parser->pos++;
    }
    return jayess_xml_copy_range(parser->input, start, parser->pos);
}

static char *jayess_xml_parse_quoted_value(jayess_xml_parser *parser) {
    int quote = jayess_xml_peek(parser);
    size_t start;
    if (quote != '"' && quote != '\'') {
        jayess_xml_fail(parser, "expected quoted XML attribute value");
        return NULL;
    }
    parser->pos++;
    start = parser->pos;
    while (parser->pos < parser->length && parser->input[parser->pos] != quote) {
        parser->pos++;
    }
    if (parser->pos >= parser->length) {
        jayess_xml_fail(parser, "unterminated XML attribute value");
        return NULL;
    }
    {
        char *value = jayess_xml_copy_range(parser->input, start, parser->pos);
        parser->pos++;
        return value;
    }
}

static jayess_xml_position jayess_xml_position_for(jayess_xml_parser *parser, size_t offset) {
    jayess_xml_position position;
    size_t index;
    position.offset = offset;
    position.line = 1;
    position.column = 1;
    for (index = 0; index < offset && index < parser->length; index++) {
        if (parser->input[index] == '\n') {
            position.line++;
            position.column = 1;
        } else {
            position.column++;
        }
    }
    return position;
}

static jayess_value *jayess_xml_position_value(jayess_xml_position position) {
    jayess_object *value = jayess_object_new();
    jayess_object_set_value(value, "offset", jayess_value_from_number((double) position.offset));
    jayess_object_set_value(value, "line", jayess_value_from_number((double) position.line));
    jayess_object_set_value(value, "column", jayess_value_from_number((double) position.column));
    return jayess_value_from_object(value);
}

static void jayess_xml_set_span(jayess_value *node, jayess_xml_parser *parser, size_t start_offset, size_t end_offset) {
    jayess_object *span = jayess_object_new();
    jayess_object_set_value(span, "start", jayess_xml_position_value(jayess_xml_position_for(parser, start_offset)));
    jayess_object_set_value(span, "end", jayess_xml_position_value(jayess_xml_position_for(parser, end_offset)));
    jayess_value_set_member(node, "span", jayess_value_from_object(span));
}

static jayess_value *jayess_xml_make_token(const char *type, jayess_xml_parser *parser, size_t start_offset, size_t end_offset) {
    jayess_object *token = jayess_object_new();
    jayess_object_set_value(token, "type", jayess_value_from_string(type));
    jayess_object_set_value(token, "span", jayess_value_undefined());
    {
        jayess_value *value = jayess_value_from_object(token);
        jayess_xml_set_span(value, parser, start_offset, end_offset);
        return value;
    }
}

static jayess_value *jayess_xml_make_document(jayess_array *children) {
    jayess_object *node = jayess_object_new();
    jayess_object_set_value(node, "type", jayess_value_from_string("document"));
    jayess_object_set_value(node, "children", jayess_value_from_array(children));
    jayess_object_set_value(node, "span", jayess_value_undefined());
    return jayess_value_from_object(node);
}

static jayess_value *jayess_xml_make_text(const char *value) {
    jayess_object *node = jayess_object_new();
    jayess_object_set_value(node, "type", jayess_value_from_string("text"));
    jayess_object_set_value(node, "value", jayess_value_from_string(value));
    jayess_object_set_value(node, "span", jayess_value_undefined());
    return jayess_value_from_object(node);
}

static jayess_value *jayess_xml_make_comment(const char *value) {
    jayess_object *node = jayess_object_new();
    jayess_object_set_value(node, "type", jayess_value_from_string("comment"));
    jayess_object_set_value(node, "value", jayess_value_from_string(value));
    jayess_object_set_value(node, "span", jayess_value_undefined());
    return jayess_value_from_object(node);
}

static jayess_value *jayess_xml_make_cdata(const char *value) {
    jayess_object *node = jayess_object_new();
    jayess_object_set_value(node, "type", jayess_value_from_string("cdata"));
    jayess_object_set_value(node, "value", jayess_value_from_string(value));
    jayess_object_set_value(node, "span", jayess_value_undefined());
    return jayess_value_from_object(node);
}

static jayess_value *jayess_xml_make_processing_instruction(const char *target, const char *data) {
    jayess_object *node = jayess_object_new();
    jayess_object_set_value(node, "type", jayess_value_from_string("processingInstruction"));
    jayess_object_set_value(node, "target", jayess_value_from_string(target));
    jayess_object_set_value(node, "data", jayess_value_from_string(data != NULL ? data : ""));
    jayess_object_set_value(node, "span", jayess_value_undefined());
    return jayess_value_from_object(node);
}

static jayess_value *jayess_xml_make_element(const char *tag_name, jayess_object *attributes, jayess_array *attribute_order, jayess_array *children, int self_closing) {
    jayess_object *node = jayess_object_new();
    jayess_object_set_value(node, "type", jayess_value_from_string("element"));
    jayess_object_set_value(node, "tagName", jayess_value_from_string(tag_name));
    jayess_object_set_value(node, "attributes", jayess_value_from_object(attributes));
    jayess_object_set_value(node, "attributeOrder", jayess_value_from_array(attribute_order));
    jayess_object_set_value(node, "children", jayess_value_from_array(children));
    jayess_object_set_value(node, "selfClosing", jayess_value_from_bool(self_closing));
    jayess_object_set_value(node, "span", jayess_value_undefined());
    return jayess_value_from_object(node);
}

static jayess_value *jayess_xml_make_start_tag_token(const char *tag_name, jayess_object *attributes, jayess_array *attribute_order, int self_closing, jayess_xml_parser *parser, size_t start_offset, size_t end_offset) {
    jayess_value *token = jayess_xml_make_token("startTag", parser, start_offset, end_offset);
    jayess_value_set_member(token, "tagName", jayess_value_from_string(tag_name));
    jayess_value_set_member(token, "attributes", jayess_value_from_object(attributes));
    jayess_value_set_member(token, "attributeOrder", jayess_value_from_array(attribute_order));
    jayess_value_set_member(token, "selfClosing", jayess_value_from_bool(self_closing));
    return token;
}

static jayess_value *jayess_xml_make_end_tag_token(const char *tag_name, jayess_xml_parser *parser, size_t start_offset, size_t end_offset) {
    jayess_value *token = jayess_xml_make_token("endTag", parser, start_offset, end_offset);
    jayess_value_set_member(token, "tagName", jayess_value_from_string(tag_name));
    return token;
}

static jayess_value *jayess_xml_make_text_token(const char *value, jayess_xml_parser *parser, size_t start_offset, size_t end_offset) {
    jayess_value *token = jayess_xml_make_token("text", parser, start_offset, end_offset);
    jayess_value_set_member(token, "value", jayess_value_from_string(value));
    return token;
}

static jayess_value *jayess_xml_make_comment_token(const char *value, jayess_xml_parser *parser, size_t start_offset, size_t end_offset) {
    jayess_value *token = jayess_xml_make_token("comment", parser, start_offset, end_offset);
    jayess_value_set_member(token, "value", jayess_value_from_string(value));
    return token;
}

static jayess_value *jayess_xml_make_cdata_token(const char *value, jayess_xml_parser *parser, size_t start_offset, size_t end_offset) {
    jayess_value *token = jayess_xml_make_token("cdata", parser, start_offset, end_offset);
    jayess_value_set_member(token, "value", jayess_value_from_string(value));
    return token;
}

static jayess_value *jayess_xml_make_processing_instruction_token(const char *target, const char *data, jayess_xml_parser *parser, size_t start_offset, size_t end_offset) {
    jayess_value *token = jayess_xml_make_token("processingInstruction", parser, start_offset, end_offset);
    jayess_value_set_member(token, "target", jayess_value_from_string(target));
    jayess_value_set_member(token, "data", jayess_value_from_string(data != NULL ? data : ""));
    return token;
}

static void jayess_xml_annotate_namespaces(jayess_value *node, jayess_xml_ns_binding *bindings) {
    const char *type = jayess_value_as_string(jayess_value_get_member(node, "type"));
    if (type == NULL) {
        return;
    }
    if (strcmp(type, "element") == 0) {
        jayess_object *attributes = jayess_value_as_object(jayess_value_get_member(node, "attributes"));
        jayess_array *attribute_order = jayess_value_as_array(jayess_value_get_member(node, "attributeOrder"));
        jayess_array *children = jayess_value_as_array(jayess_value_get_member(node, "children"));
        jayess_object *attribute_details = jayess_object_new();
        jayess_xml_ns_binding *current_bindings = bindings;
        jayess_xml_ns_binding *binding_stop = bindings;
        const char *tag_name = jayess_value_as_string(jayess_value_get_member(node, "tagName"));
        char *prefix = NULL;
        char *local_name = NULL;
        int index;

        if (attribute_order != NULL && attributes != NULL) {
            for (index = 0; index < jayess_array_length(attribute_order); index++) {
                const char *attr_name = jayess_value_as_string(jayess_array_get(attribute_order, index));
                const char *attr_value = jayess_value_as_string(jayess_object_get(attributes, attr_name));
                if (attr_name == NULL || attr_value == NULL) {
                    continue;
                }
                if (strcmp(attr_name, "xmlns") == 0) {
                    current_bindings = jayess_xml_push_ns_binding(current_bindings, "", attr_value);
                } else if (strncmp(attr_name, "xmlns:", 6) == 0) {
                    current_bindings = jayess_xml_push_ns_binding(current_bindings, attr_name + 6, attr_value);
                }
            }
        }

        jayess_xml_split_name(tag_name, &prefix, &local_name);
        if (prefix != NULL) {
            jayess_value_set_member(node, "prefix", jayess_value_from_string(prefix));
        } else {
            jayess_value_set_member(node, "prefix", jayess_value_undefined());
        }
        jayess_value_set_member(node, "localName", jayess_value_from_string(local_name != NULL ? local_name : ""));
        {
            const char *namespace_uri = jayess_xml_lookup_ns(current_bindings, prefix);
            if (namespace_uri != NULL && namespace_uri[0] != '\0') {
                jayess_value_set_member(node, "namespaceURI", jayess_value_from_string(namespace_uri));
            } else {
                jayess_value_set_member(node, "namespaceURI", jayess_value_undefined());
            }
        }
        free(prefix);
        free(local_name);

        if (attribute_order != NULL && attributes != NULL) {
            for (index = 0; index < jayess_array_length(attribute_order); index++) {
                const char *attr_name = jayess_value_as_string(jayess_array_get(attribute_order, index));
                jayess_object *detail;
                char *attr_prefix = NULL;
                char *attr_local_name = NULL;
                const char *namespace_uri;
                if (attr_name == NULL) {
                    continue;
                }
                detail = jayess_object_new();
                jayess_xml_split_name(attr_name, &attr_prefix, &attr_local_name);
                if (attr_prefix != NULL) {
                    jayess_object_set_value(detail, "prefix", jayess_value_from_string(attr_prefix));
                } else {
                    jayess_object_set_value(detail, "prefix", jayess_value_undefined());
                }
                jayess_object_set_value(detail, "localName", jayess_value_from_string(attr_local_name != NULL ? attr_local_name : ""));
                if (strcmp(attr_name, "xmlns") == 0) {
                    jayess_object_set_value(detail, "namespaceURI", jayess_value_from_string("http://www.w3.org/2000/xmlns/"));
                } else if (strncmp(attr_name, "xmlns:", 6) == 0) {
                    jayess_object_set_value(detail, "namespaceURI", jayess_value_from_string("http://www.w3.org/2000/xmlns/"));
                } else {
                    namespace_uri = attr_prefix != NULL ? jayess_xml_lookup_ns(current_bindings, attr_prefix) : NULL;
                    if (namespace_uri != NULL && namespace_uri[0] != '\0') {
                        jayess_object_set_value(detail, "namespaceURI", jayess_value_from_string(namespace_uri));
                    } else {
                        jayess_object_set_value(detail, "namespaceURI", jayess_value_undefined());
                    }
                }
                jayess_object_set_value(attribute_details, attr_name, jayess_value_from_object(detail));
                free(attr_prefix);
                free(attr_local_name);
            }
        }
        jayess_value_set_member(node, "attributeDetails", jayess_value_from_object(attribute_details));

        if (children != NULL) {
            for (index = 0; index < jayess_array_length(children); index++) {
                jayess_xml_annotate_namespaces(jayess_array_get(children, index), current_bindings);
            }
        }
        jayess_xml_free_ns_bindings_until(current_bindings, binding_stop);
        return;
    }
    if (strcmp(type, "document") == 0) {
        jayess_array *children = jayess_value_as_array(jayess_value_get_member(node, "children"));
        int index;
        if (children == NULL) {
            return;
        }
        for (index = 0; index < jayess_array_length(children); index++) {
            jayess_xml_annotate_namespaces(jayess_array_get(children, index), bindings);
        }
    }
}

static jayess_value *jayess_xml_parse_comment_node(jayess_xml_parser *parser);
static jayess_value *jayess_xml_parse_cdata_node(jayess_xml_parser *parser);
static jayess_value *jayess_xml_parse_processing_instruction_node(jayess_xml_parser *parser);
static jayess_value *jayess_xml_parse_element(jayess_xml_parser *parser);

static int jayess_xml_parse_misc_node(jayess_xml_parser *parser, jayess_array *children, int top_level) {
    if (jayess_xml_has_prefix(parser, "<!--")) {
        jayess_array_push_value(children, jayess_xml_parse_comment_node(parser));
        return 1;
    }
    if (jayess_xml_has_prefix(parser, "<?")) {
        jayess_array_push_value(children, jayess_xml_parse_processing_instruction_node(parser));
        return 1;
    }
    if (!top_level && jayess_xml_has_prefix(parser, "<![CDATA[")) {
        jayess_array_push_value(children, jayess_xml_parse_cdata_node(parser));
        return 1;
    }
    return 0;
}

static jayess_value *jayess_xml_parse_comment_node(jayess_xml_parser *parser) {
    size_t start_offset = parser->pos;
    size_t value_start;
    size_t value_end;
    char *value;
    parser->pos += 4;
    value_start = parser->pos;
    while (parser->pos + 2 < parser->length && !jayess_xml_has_prefix(parser, "-->")) {
        parser->pos++;
    }
    if (!jayess_xml_has_prefix(parser, "-->")) {
        jayess_xml_fail(parser, "unterminated XML comment");
        return jayess_value_undefined();
    }
    value_end = parser->pos;
    value = jayess_xml_copy_range(parser->input, value_start, value_end);
    parser->pos += 3;
    {
        jayess_value *node = jayess_xml_make_comment(value != NULL ? value : "");
        jayess_xml_set_span(node, parser, start_offset, parser->pos);
        free(value);
        return node;
    }
}

static jayess_value *jayess_xml_parse_cdata_node(jayess_xml_parser *parser) {
    size_t start_offset = parser->pos;
    size_t value_start;
    size_t value_end;
    char *value;
    parser->pos += 9;
    value_start = parser->pos;
    while (parser->pos + 2 < parser->length && !jayess_xml_has_prefix(parser, "]]>")) {
        parser->pos++;
    }
    if (!jayess_xml_has_prefix(parser, "]]>")) {
        jayess_xml_fail(parser, "unterminated XML CDATA section");
        return jayess_value_undefined();
    }
    value_end = parser->pos;
    value = jayess_xml_copy_range(parser->input, value_start, value_end);
    parser->pos += 3;
    {
        jayess_value *node = jayess_xml_make_cdata(value != NULL ? value : "");
        jayess_xml_set_span(node, parser, start_offset, parser->pos);
        free(value);
        return node;
    }
}

static jayess_value *jayess_xml_parse_processing_instruction_node(jayess_xml_parser *parser) {
    size_t start_offset = parser->pos;
    char *target;
    char *data = NULL;
    parser->pos += 2;
    target = jayess_xml_parse_name(parser);
    if (target == NULL) {
        jayess_xml_fail(parser, "expected XML processing instruction target");
        return jayess_value_undefined();
    }
    jayess_xml_skip_ws(parser);
    {
        size_t data_start = parser->pos;
        size_t data_end;
        while (parser->pos + 1 < parser->length && !jayess_xml_has_prefix(parser, "?>")) {
            parser->pos++;
        }
        if (!jayess_xml_has_prefix(parser, "?>")) {
            free(target);
            jayess_xml_fail(parser, "unterminated XML processing instruction");
            return jayess_value_undefined();
        }
        data_end = parser->pos;
        while (data_end > data_start && isspace((unsigned char) parser->input[data_end - 1])) {
            data_end--;
        }
        data = jayess_xml_copy_range(parser->input, data_start, data_end);
    }
    parser->pos += 2;
    {
        jayess_value *node = jayess_xml_make_processing_instruction(target, data != NULL ? data : "");
        jayess_xml_set_span(node, parser, start_offset, parser->pos);
        free(target);
        free(data);
        return node;
    }
}

static jayess_array *jayess_xml_parse_children(jayess_xml_parser *parser, const char *closing_tag) {
    jayess_array *children = jayess_array_new();
    while (parser->pos < parser->length) {
        if (jayess_xml_has_prefix(parser, "</")) {
            size_t closing_start = parser->pos;
            char *name;
            parser->pos += 2;
            jayess_xml_skip_ws(parser);
            name = jayess_xml_parse_name(parser);
            jayess_xml_skip_ws(parser);
            if (name == NULL) {
                jayess_xml_fail(parser, "expected XML closing tag name");
                return children;
            }
            if (jayess_xml_peek(parser) != '>') {
                free(name);
                jayess_xml_fail(parser, "expected > after XML closing tag");
                return children;
            }
            parser->pos++;
            if (closing_tag == NULL || strcmp(name, closing_tag) != 0) {
                free(name);
                jayess_xml_fail(parser, "mismatched XML closing tag");
                parser->pos = closing_start;
                return children;
            }
            free(name);
            return children;
        }
        if (jayess_xml_parse_misc_node(parser, children, 0)) {
            if (parser->error != NULL || jayess_has_exception()) {
                return children;
            }
            continue;
        }
        if (jayess_xml_peek(parser) == '<') {
            jayess_array_push_value(children, jayess_xml_parse_element(parser));
            if (parser->error != NULL || jayess_has_exception()) {
                return children;
            }
            continue;
        }
        {
            size_t start = parser->pos;
            char *text;
            while (parser->pos < parser->length && parser->input[parser->pos] != '<') {
                parser->pos++;
            }
            text = jayess_xml_copy_range(parser->input, start, parser->pos);
            if (text != NULL && text[0] != '\0') {
                jayess_value *node = jayess_xml_make_text(text);
                jayess_xml_set_span(node, parser, start, parser->pos);
                jayess_array_push_value(children, node);
            }
            free(text);
        }
    }
    if (closing_tag != NULL) {
        jayess_xml_fail(parser, "missing XML closing tag");
    }
    return children;
}

static jayess_value *jayess_xml_parse_element(jayess_xml_parser *parser) {
    size_t start_offset = parser->pos;
    char *tag_name;
    jayess_object *attributes;
    jayess_array *attribute_order;
    jayess_array *children;
    int self_closing = 0;
    if (jayess_xml_peek(parser) != '<') {
        jayess_xml_fail(parser, "expected XML element");
        return jayess_value_undefined();
    }
    parser->pos++;
    tag_name = jayess_xml_parse_name(parser);
    if (tag_name == NULL) {
        jayess_xml_fail(parser, "expected XML tag name");
        return jayess_value_undefined();
    }
    attributes = jayess_object_new();
    attribute_order = jayess_array_new();
    while (parser->pos < parser->length) {
        char *attr_name;
        char *attr_value;
        jayess_xml_skip_ws(parser);
        if (jayess_xml_has_prefix(parser, "/>")) {
            self_closing = 1;
            parser->pos += 2;
            break;
        }
        if (jayess_xml_peek(parser) == '>') {
            parser->pos++;
            break;
        }
        attr_name = jayess_xml_parse_name(parser);
        if (attr_name == NULL) {
            free(tag_name);
            jayess_xml_fail(parser, "expected XML attribute name");
            return jayess_value_undefined();
        }
        jayess_xml_skip_ws(parser);
        if (jayess_xml_peek(parser) != '=') {
            free(attr_name);
            free(tag_name);
            jayess_xml_fail(parser, "expected = after XML attribute name");
            return jayess_value_undefined();
        }
        parser->pos++;
        jayess_xml_skip_ws(parser);
        attr_value = jayess_xml_parse_quoted_value(parser);
        if (attr_value == NULL) {
            free(attr_name);
            free(tag_name);
            return jayess_value_undefined();
        }
        jayess_array_push_value(attribute_order, jayess_value_from_string(attr_name));
        jayess_object_set_value(attributes, attr_name, jayess_value_from_string(attr_value));
        free(attr_name);
        free(attr_value);
    }
    if (self_closing) {
        jayess_value *node = jayess_xml_make_element(tag_name, attributes, attribute_order, jayess_array_new(), 1);
        jayess_xml_set_span(node, parser, start_offset, parser->pos);
        free(tag_name);
        return node;
    }
    children = jayess_xml_parse_children(parser, tag_name);
    if (parser->error != NULL || jayess_has_exception()) {
        free(tag_name);
        return jayess_value_undefined();
    }
    {
        jayess_value *node = jayess_xml_make_element(tag_name, attributes, attribute_order, children, 0);
        jayess_xml_set_span(node, parser, start_offset, parser->pos);
        free(tag_name);
        return node;
    }
}

static jayess_value *jayess_xml_tokenize_or_parse_common(jayess_value *input_value, int parse_mode) {
    const char *input = jayess_expect_string(input_value, parse_mode ? "jayess_xml_parse_document" : "jayess_xml_tokenize");
    char *owned_input;
    jayess_xml_parser parser;
    jayess_array *items;
    int seen_root = 0;
    if (jayess_has_exception()) {
        return jayess_value_undefined();
    }
    owned_input = jayess_xml_strdup(input);
    if (owned_input == NULL) {
        return jayess_value_undefined();
    }
    parser.input = owned_input;
    parser.length = strlen(input);
    parser.pos = 0;
    parser.error = NULL;
    items = jayess_array_new();
    while (parser.pos < parser.length) {
        size_t text_start;
        if (isspace((unsigned char) jayess_xml_peek(&parser))) {
            jayess_xml_skip_ws(&parser);
            continue;
        }
        if (jayess_xml_parse_misc_node(&parser, items, 1)) {
            if (parser.error != NULL || jayess_has_exception()) {
                break;
            }
            continue;
        }
        if (jayess_xml_has_prefix(&parser, "<![CDATA[")) {
            jayess_xml_fail(&parser, "CDATA is only allowed inside XML elements");
            break;
        }
        if (jayess_xml_has_prefix(&parser, "</")) {
            jayess_xml_fail(&parser, "unexpected XML closing tag");
            break;
        }
        if (jayess_xml_peek(&parser) == '<') {
            if (parse_mode) {
                if (seen_root) {
                    jayess_xml_fail(&parser, "XML document must contain exactly one root element");
                    break;
                }
                jayess_array_push_value(items, jayess_xml_parse_element(&parser));
                seen_root = 1;
            } else {
                size_t token_start = parser.pos;
                char *tag_name;
                jayess_object *attributes;
                jayess_array *attribute_order;
                int self_closing = 0;
                parser.pos++;
                tag_name = jayess_xml_parse_name(&parser);
                if (tag_name == NULL) {
                    jayess_xml_fail(&parser, "expected XML tag name");
                    break;
                }
                attributes = jayess_object_new();
                attribute_order = jayess_array_new();
                while (parser.pos < parser.length) {
                    char *attr_name;
                    char *attr_value;
                    jayess_xml_skip_ws(&parser);
                    if (jayess_xml_has_prefix(&parser, "/>")) {
                        self_closing = 1;
                        parser.pos += 2;
                        break;
                    }
                    if (jayess_xml_peek(&parser) == '>') {
                        parser.pos++;
                        break;
                    }
                    attr_name = jayess_xml_parse_name(&parser);
                    if (attr_name == NULL) {
                        jayess_xml_free_partial_object(attributes);
                        jayess_xml_free_partial_array(attribute_order);
                        free(tag_name);
                        jayess_xml_fail(&parser, "expected XML attribute name");
                        break;
                    }
                    jayess_xml_skip_ws(&parser);
                    if (jayess_xml_peek(&parser) != '=') {
                        free(attr_name);
                        jayess_xml_free_partial_object(attributes);
                        jayess_xml_free_partial_array(attribute_order);
                        free(tag_name);
                        jayess_xml_fail(&parser, "expected = after XML attribute name");
                        break;
                    }
                    parser.pos++;
                    jayess_xml_skip_ws(&parser);
                    attr_value = jayess_xml_parse_quoted_value(&parser);
                    if (attr_value == NULL) {
                        free(attr_name);
                        jayess_xml_free_partial_object(attributes);
                        jayess_xml_free_partial_array(attribute_order);
                        free(tag_name);
                        break;
                    }
                    jayess_array_push_value(attribute_order, jayess_value_from_string(attr_name));
                    jayess_object_set_value(attributes, attr_name, jayess_value_from_string(attr_value));
                    free(attr_name);
                    free(attr_value);
                }
                if (parser.error != NULL) {
                    break;
                }
                jayess_array_push_value(items, jayess_xml_make_start_tag_token(tag_name, attributes, attribute_order, self_closing, &parser, token_start, parser.pos));
                free(tag_name);
            }
            if (parser.error != NULL || jayess_has_exception()) {
                break;
            }
            continue;
        }
        text_start = parser.pos;
        while (parser.pos < parser.length && parser.input[parser.pos] != '<') {
            parser.pos++;
        }
        {
            char *text = jayess_xml_copy_range(parser.input, text_start, parser.pos);
            int whitespace_only = 1;
            size_t index;
            if (text != NULL) {
                for (index = 0; text[index] != '\0'; index++) {
                    if (!isspace((unsigned char) text[index])) {
                        whitespace_only = 0;
                        break;
                    }
                }
                if (parse_mode) {
                    if (!whitespace_only) {
                        jayess_xml_fail(&parser, "unexpected top-level XML text");
                        free(text);
                        break;
                    }
                } else if (text[0] != '\0') {
                    jayess_array_push_value(items, jayess_xml_make_text_token(text, &parser, text_start, parser.pos));
                }
            }
            free(text);
        }
    }
    if (parser.error != NULL) {
        jayess_xml_free_partial_array(items);
        free(owned_input);
        jayess_throw_named_error("XMLParseError", parser.error);
        return jayess_value_undefined();
    }
    if (parse_mode) {
        jayess_value *document;
        if (!seen_root) {
            jayess_xml_free_partial_array(items);
            free(owned_input);
            jayess_throw_named_error("XMLParseError", "XML document missing root element");
            return jayess_value_undefined();
        }
        document = jayess_xml_make_document(items);
        jayess_xml_set_span(document, &parser, 0, parser.pos);
        free(owned_input);
        return document;
    }
    free(owned_input);
    return jayess_value_from_array(items);
}

static void jayess_xml_buffer_append_bytes(jayess_xml_buffer *buffer, const char *text, size_t length) {
    size_t required;
    char *grown;
    if (buffer->failed || text == NULL || length == 0) {
        return;
    }
    required = buffer->length + length + 1;
    if (required > buffer->capacity) {
        size_t next_capacity = buffer->capacity == 0 ? 64 : buffer->capacity;
        while (next_capacity < required) {
            next_capacity *= 2;
        }
        grown = (char *) realloc(buffer->data, next_capacity);
        if (grown == NULL) {
            buffer->failed = 1;
            return;
        }
        buffer->data = grown;
        buffer->capacity = next_capacity;
    }
    memcpy(buffer->data + buffer->length, text, length);
    buffer->length += length;
    buffer->data[buffer->length] = '\0';
}

static void jayess_xml_buffer_append_cstr(jayess_xml_buffer *buffer, const char *text) {
    if (text != NULL) {
        jayess_xml_buffer_append_bytes(buffer, text, strlen(text));
    }
}

static int jayess_xml_serialize_preserve_comments(jayess_value *options) {
    jayess_value *comments_value;
    if (options == NULL || jayess_value_kind_of(options) == JAYESS_VALUE_UNDEFINED || jayess_value_kind_of(options) == JAYESS_VALUE_NULL) {
        return 1;
    }
    comments_value = jayess_value_get_member(options, "comments");
    if (comments_value == NULL || jayess_value_kind_of(comments_value) == JAYESS_VALUE_UNDEFINED) {
        return 1;
    }
    return jayess_value_as_bool(comments_value);
}

static int jayess_xml_serialize_pretty(jayess_value *options) {
    jayess_value *pretty_value;
    if (options == NULL || jayess_value_kind_of(options) == JAYESS_VALUE_UNDEFINED || jayess_value_kind_of(options) == JAYESS_VALUE_NULL) {
        return 0;
    }
    pretty_value = jayess_value_get_member(options, "pretty");
    if (pretty_value == NULL || jayess_value_kind_of(pretty_value) == JAYESS_VALUE_UNDEFINED) {
        return 0;
    }
    return jayess_value_as_bool(pretty_value);
}

static int jayess_xml_serialize_minify(jayess_value *options) {
    jayess_value *minify_value;
    if (options == NULL || jayess_value_kind_of(options) == JAYESS_VALUE_UNDEFINED || jayess_value_kind_of(options) == JAYESS_VALUE_NULL) {
        return 0;
    }
    minify_value = jayess_value_get_member(options, "minify");
    if (minify_value == NULL || jayess_value_kind_of(minify_value) == JAYESS_VALUE_UNDEFINED) {
        return 0;
    }
    return jayess_value_as_bool(minify_value);
}

static void jayess_xml_buffer_indent(jayess_xml_buffer *buffer, int depth) {
    int index;
    for (index = 0; index < depth; index++) {
        jayess_xml_buffer_append_cstr(buffer, "  ");
    }
}

static int jayess_xml_children_are_inline_text(jayess_array *children) {
    int index;
    if (children == NULL || jayess_array_length(children) == 0) {
        return 1;
    }
    for (index = 0; index < jayess_array_length(children); index++) {
        jayess_value *child = jayess_array_get(children, index);
        const char *type = jayess_value_as_string(jayess_value_get_member(child, "type"));
        if (type == NULL || strcmp(type, "text") != 0) {
            return 0;
        }
    }
    return 1;
}

static void jayess_xml_serialize_value(jayess_value *node, jayess_xml_buffer *buffer, int preserve_comments, int pretty, int depth);

static void jayess_xml_serialize_children(jayess_value *node, jayess_xml_buffer *buffer, int preserve_comments, int pretty, int depth) {
    jayess_array *children = jayess_value_as_array(jayess_value_get_member(node, "children"));
    int index;
    if (children == NULL) {
        return;
    }
    for (index = 0; index < jayess_array_length(children); index++) {
        jayess_xml_serialize_value(jayess_array_get(children, index), buffer, preserve_comments, pretty, depth);
    }
}

static void jayess_xml_serialize_value(jayess_value *node, jayess_xml_buffer *buffer, int preserve_comments, int pretty, int depth) {
    const char *type = jayess_value_as_string(jayess_value_get_member(node, "type"));
    if (type == NULL || buffer->failed) {
        return;
    }
    if (strcmp(type, "document") == 0) {
        jayess_xml_serialize_children(node, buffer, preserve_comments, pretty, depth);
        return;
    }
    if (strcmp(type, "text") == 0) {
        jayess_xml_buffer_append_cstr(buffer, jayess_value_as_string(jayess_value_get_member(node, "value")));
        return;
    }
    if (strcmp(type, "comment") == 0) {
        if (!preserve_comments) {
            return;
        }
        jayess_xml_buffer_append_cstr(buffer, "<!--");
        jayess_xml_buffer_append_cstr(buffer, jayess_value_as_string(jayess_value_get_member(node, "value")));
        jayess_xml_buffer_append_cstr(buffer, "-->");
        return;
    }
    if (strcmp(type, "cdata") == 0) {
        jayess_xml_buffer_append_cstr(buffer, "<![CDATA[");
        jayess_xml_buffer_append_cstr(buffer, jayess_value_as_string(jayess_value_get_member(node, "value")));
        jayess_xml_buffer_append_cstr(buffer, "]]>");
        return;
    }
    if (strcmp(type, "processingInstruction") == 0) {
        const char *target = jayess_value_as_string(jayess_value_get_member(node, "target"));
        const char *data = jayess_value_as_string(jayess_value_get_member(node, "data"));
        jayess_xml_buffer_append_cstr(buffer, "<?");
        jayess_xml_buffer_append_cstr(buffer, target != NULL ? target : "");
        if (data != NULL && data[0] != '\0') {
            jayess_xml_buffer_append_cstr(buffer, " ");
            jayess_xml_buffer_append_cstr(buffer, data);
        }
        jayess_xml_buffer_append_cstr(buffer, "?>");
        return;
    }
    if (strcmp(type, "element") == 0) {
        const char *tag_name = jayess_value_as_string(jayess_value_get_member(node, "tagName"));
        jayess_object *attributes = jayess_value_as_object(jayess_value_get_member(node, "attributes"));
        jayess_array *attribute_order = jayess_value_as_array(jayess_value_get_member(node, "attributeOrder"));
        jayess_array *children = jayess_value_as_array(jayess_value_get_member(node, "children"));
        int self_closing = jayess_value_as_bool(jayess_value_get_member(node, "selfClosing"));
        int index;
        jayess_xml_buffer_append_cstr(buffer, "<");
        jayess_xml_buffer_append_cstr(buffer, tag_name != NULL ? tag_name : "");
        if (attribute_order != NULL && attributes != NULL) {
            for (index = 0; index < jayess_array_length(attribute_order); index++) {
                const char *name = jayess_value_as_string(jayess_array_get(attribute_order, index));
                if (name != NULL) {
                    jayess_xml_buffer_append_cstr(buffer, " ");
                    jayess_xml_buffer_append_cstr(buffer, name);
                    jayess_xml_buffer_append_cstr(buffer, "=\"");
                    jayess_xml_buffer_append_cstr(buffer, jayess_value_as_string(jayess_object_get(attributes, name)));
                    jayess_xml_buffer_append_cstr(buffer, "\"");
                }
            }
        }
        if (self_closing && (children == NULL || jayess_array_length(children) == 0)) {
            jayess_xml_buffer_append_cstr(buffer, "/>");
            return;
        }
        jayess_xml_buffer_append_cstr(buffer, ">");
        if (pretty && !jayess_xml_children_are_inline_text(children) && children != NULL && jayess_array_length(children) > 0) {
            int emitted_child = 0;
            for (index = 0; index < jayess_array_length(children); index++) {
                jayess_value *child = jayess_array_get(children, index);
                const char *child_type = jayess_value_as_string(jayess_value_get_member(child, "type"));
                if (!preserve_comments && child_type != NULL && strcmp(child_type, "comment") == 0) {
                    continue;
                }
                jayess_xml_buffer_append_cstr(buffer, "\n");
                jayess_xml_buffer_indent(buffer, depth + 1);
                jayess_xml_serialize_value(child, buffer, preserve_comments, pretty, depth + 1);
                emitted_child = 1;
            }
            if (emitted_child) {
                jayess_xml_buffer_append_cstr(buffer, "\n");
                jayess_xml_buffer_indent(buffer, depth);
            }
        } else {
            jayess_xml_serialize_children(node, buffer, preserve_comments, pretty, depth + 1);
        }
        jayess_xml_buffer_append_cstr(buffer, "</");
        jayess_xml_buffer_append_cstr(buffer, tag_name != NULL ? tag_name : "");
        jayess_xml_buffer_append_cstr(buffer, ">");
    }
}

jayess_value *jayess_xml_tokenize(jayess_value *input_value) {
    const char *input = jayess_expect_string(input_value, "jayess_xml_tokenize");
    char *owned_input;
    jayess_xml_parser parser;
    jayess_array *tokens;
    if (jayess_has_exception()) {
        return jayess_value_undefined();
    }
    owned_input = jayess_xml_strdup(input);
    if (owned_input == NULL) {
        return jayess_value_undefined();
    }
    parser.input = owned_input;
    parser.length = strlen(input);
    parser.pos = 0;
    parser.error = NULL;
    tokens = jayess_array_new();
    while (parser.pos < parser.length) {
        if (jayess_xml_has_prefix(&parser, "<!--")) {
            size_t start_offset = parser.pos;
            size_t value_start;
            size_t value_end;
            char *value;
            parser.pos += 4;
            value_start = parser.pos;
            while (parser.pos + 2 < parser.length && !jayess_xml_has_prefix(&parser, "-->")) {
                parser.pos++;
            }
            if (!jayess_xml_has_prefix(&parser, "-->")) {
                parser.error = "unterminated XML comment";
                break;
            }
            value_end = parser.pos;
            value = jayess_xml_copy_range(parser.input, value_start, value_end);
            parser.pos += 3;
            jayess_array_push_value(tokens, jayess_xml_make_comment_token(value != NULL ? value : "", &parser, start_offset, parser.pos));
            free(value);
            continue;
        }
        if (jayess_xml_has_prefix(&parser, "<![CDATA[")) {
            size_t start_offset = parser.pos;
            size_t value_start;
            size_t value_end;
            char *value;
            parser.pos += 9;
            value_start = parser.pos;
            while (parser.pos + 2 < parser.length && !jayess_xml_has_prefix(&parser, "]]>")) {
                parser.pos++;
            }
            if (!jayess_xml_has_prefix(&parser, "]]>")) {
                parser.error = "unterminated XML CDATA section";
                break;
            }
            value_end = parser.pos;
            value = jayess_xml_copy_range(parser.input, value_start, value_end);
            parser.pos += 3;
            jayess_array_push_value(tokens, jayess_xml_make_cdata_token(value != NULL ? value : "", &parser, start_offset, parser.pos));
            free(value);
            continue;
        }
        if (jayess_xml_has_prefix(&parser, "<?")) {
            size_t start_offset = parser.pos;
            char *target;
            char *data;
            size_t data_start;
            size_t data_end;
            parser.pos += 2;
            target = jayess_xml_parse_name(&parser);
            if (target == NULL) {
                parser.error = "expected XML processing instruction target";
                break;
            }
            jayess_xml_skip_ws(&parser);
            data_start = parser.pos;
            while (parser.pos + 1 < parser.length && !jayess_xml_has_prefix(&parser, "?>")) {
                parser.pos++;
            }
            if (!jayess_xml_has_prefix(&parser, "?>")) {
                free(target);
                parser.error = "unterminated XML processing instruction";
                break;
            }
            data_end = parser.pos;
            while (data_end > data_start && isspace((unsigned char) parser.input[data_end - 1])) {
                data_end--;
            }
            data = jayess_xml_copy_range(parser.input, data_start, data_end);
            parser.pos += 2;
            jayess_array_push_value(tokens, jayess_xml_make_processing_instruction_token(target, data != NULL ? data : "", &parser, start_offset, parser.pos));
            free(target);
            free(data);
            continue;
        }
        if (jayess_xml_has_prefix(&parser, "</")) {
            size_t start_offset = parser.pos;
            char *tag_name;
            parser.pos += 2;
            jayess_xml_skip_ws(&parser);
            tag_name = jayess_xml_parse_name(&parser);
            if (tag_name == NULL) {
                parser.error = "expected XML closing tag name";
                break;
            }
            jayess_xml_skip_ws(&parser);
            if (jayess_xml_peek(&parser) != '>') {
                free(tag_name);
                parser.error = "expected > after XML closing tag";
                break;
            }
            parser.pos++;
            jayess_array_push_value(tokens, jayess_xml_make_end_tag_token(tag_name, &parser, start_offset, parser.pos));
            free(tag_name);
            continue;
        }
        if (jayess_xml_peek(&parser) == '<') {
            size_t start_offset = parser.pos;
            char *tag_name;
            jayess_object *attributes;
            jayess_array *attribute_order;
            int self_closing = 0;
            parser.pos++;
            tag_name = jayess_xml_parse_name(&parser);
            if (tag_name == NULL) {
                parser.error = "expected XML tag name";
                break;
            }
            attributes = jayess_object_new();
            attribute_order = jayess_array_new();
            while (parser.pos < parser.length) {
                char *attr_name;
                char *attr_value;
                jayess_xml_skip_ws(&parser);
                if (jayess_xml_has_prefix(&parser, "/>")) {
                    self_closing = 1;
                    parser.pos += 2;
                    break;
                }
                if (jayess_xml_peek(&parser) == '>') {
                    parser.pos++;
                    break;
                }
                attr_name = jayess_xml_parse_name(&parser);
                if (attr_name == NULL) {
                    jayess_xml_free_partial_object(attributes);
                    jayess_xml_free_partial_array(attribute_order);
                    free(tag_name);
                    parser.error = "expected XML attribute name";
                    break;
                }
                jayess_xml_skip_ws(&parser);
                if (jayess_xml_peek(&parser) != '=') {
                    free(attr_name);
                    jayess_xml_free_partial_object(attributes);
                    jayess_xml_free_partial_array(attribute_order);
                    free(tag_name);
                    parser.error = "expected = after XML attribute name";
                    break;
                }
                parser.pos++;
                jayess_xml_skip_ws(&parser);
                attr_value = jayess_xml_parse_quoted_value(&parser);
                if (attr_value == NULL) {
                    free(attr_name);
                    jayess_xml_free_partial_object(attributes);
                    jayess_xml_free_partial_array(attribute_order);
                    free(tag_name);
                    break;
                }
                jayess_array_push_value(attribute_order, jayess_value_from_string(attr_name));
                jayess_object_set_value(attributes, attr_name, jayess_value_from_string(attr_value));
                free(attr_name);
                free(attr_value);
            }
            if (parser.error != NULL) {
                break;
            }
            jayess_array_push_value(tokens, jayess_xml_make_start_tag_token(tag_name, attributes, attribute_order, self_closing, &parser, start_offset, parser.pos));
            free(tag_name);
            continue;
        }
        {
            size_t start_offset = parser.pos;
            char *text;
            while (parser.pos < parser.length && parser.input[parser.pos] != '<') {
                parser.pos++;
            }
            text = jayess_xml_copy_range(parser.input, start_offset, parser.pos);
            if (text != NULL && text[0] != '\0') {
                jayess_array_push_value(tokens, jayess_xml_make_text_token(text, &parser, start_offset, parser.pos));
            }
            free(text);
        }
    }
    if (parser.error != NULL) {
        jayess_xml_free_partial_array(tokens);
        free(owned_input);
        jayess_throw_named_error("XMLParseError", parser.error);
        return jayess_value_undefined();
    }
    free(owned_input);
    return jayess_value_from_array(tokens);
}

jayess_value *jayess_xml_parse_document(jayess_value *input_value) {
    jayess_value *document = jayess_xml_tokenize_or_parse_common(input_value, 1);
    if (!jayess_has_exception()) {
        jayess_xml_annotate_namespaces(document, NULL);
    }
    return document;
}

jayess_value *jayess_xml_serialize(jayess_value *node, jayess_value *options) {
    jayess_xml_buffer buffer;
    int preserve_comments = jayess_xml_serialize_preserve_comments(options);
    int pretty = jayess_xml_serialize_pretty(options);
    int minify = jayess_xml_serialize_minify(options);
    if (minify) {
        pretty = 0;
    }
    buffer.data = NULL;
    buffer.length = 0;
    buffer.capacity = 0;
    buffer.failed = 0;
    jayess_xml_serialize_value(node, &buffer, preserve_comments, pretty, 0);
    if (buffer.failed) {
        free(buffer.data);
        jayess_throw_named_error("XMLSerializeError", "failed to serialize XML");
        return jayess_value_undefined();
    }
    if (buffer.data == NULL) {
        return jayess_value_from_string("");
    }
    {
        jayess_value *result = jayess_value_from_string(buffer.data);
        free(buffer.data);
        return result;
    }
}
